import React, { useState, useEffect, useRef } from 'react'
import {
  CCardHeader,
  CButton,
  CCard,
  CCardBody,
  CRow,
  CCol,
  CForm,
  CFormInput,
  CFormFloating,
  CFormLabel,
  CFormSelect,
  CFormTextarea,
  CModal,
  CModalBody,
  CModalFooter,
  CModalTitle,
  CModalHeader,
  CSpinner,
  CToaster,
} from '@coreui/react'
import axios from 'axios'
import FlutterPayment from 'src/utils/FlutterPayment'
import { getStudentDetails, getUser } from 'src/utils/Auth'
import RemitaConfig from 'src/utils/RemitaConfig'
import Notify from 'src/utils/Notify'

const AppForm = () => {
  const [fields, setFields] = useState({
    transcript_type: '',
    mode: '',
    email: '',
    destination: '',
    address: 'WES',
    recipient: '',
    gradstat: '',
    graduation_year: '',
    certificate: null,
    reference: '',
    institutional_username: '',
    institutional_password: '',
  })
  const [amount, setAmount] = useState(null)
  const [loading, setLoading] = useState(false)
  const [paymentModal, setPaymentModal] = useState(false)
  const [validated, setValidated] = useState(false)
  const [destFromServer, setDestFromServer] = useState(null)
  const [error, setError] = useState(false)
  const [toast, addToast] = useState(0)
  const [message, setMessage] = useState(null)
  const toaster = useRef()

  const user = getUser()
  const studentDetails = getStudentDetails()

  useEffect(() => {
    const getDestination = async () => {
      const resFromServer = await fetchDestination()
      resFromServer ? setDestFromServer(resFromServer) : setDestFromServer(null)
    }
    getDestination()
  }, [])

  useEffect(() => {
    if (message) addToast(notify)
  }, [message])

  const notify = <Notify error={error} message={message} />

  let startYear = 2009
  let thisYear = new Date().getFullYear()
  let offset = thisYear - startYear
  let allYears = []
  for (let x = 0; x <= offset; x++) {
    allYears.push(startYear + x)
  }

  const yearList = allYears.map((x) => {
    return (
      <option value={x} key={x}>
        {x}
      </option>
    )
  })

  const fetchDestination = async () => {
    const res = await fetch(
      'https://records.run.edu.ng/api/app/get_transcript_destination_and_amount',
    )
    const data = await res.json()
    return data
  }

  const handleChange = (e) => {
    const { id, value } = e.target
    if (value === 'Student' || value === 'proficiency') {
      setFields((prevState) => ({
        ...prevState,
        mode: value,
        address: '',
      }))
    }
    setFields((prevState) => ({
      ...prevState,
      [id]: value,
    }))
    console.log(fields)
    const selectedIndex = e.target.options.selectedIndex
    //console.log(e.target.options[selectedIndex].getAttribute('data-amount'))
    selectedIndex && setAmount(e.target.options[selectedIndex].getAttribute('data-amount'))
  }

  const onFileChange = (e) => {
    //console.log(URL.createObjectURL(e.target.files[0]))
    console.log(e.target.files[0])
    setFields((prevState) => ({
      ...prevState,
      certificate: e.target.files[0],
    }))
  }

  const checkApplicantValidity = () => {
    setLoading(true)
    setMessage(null)
    setError(null)
    axios
      .get('https://records.run.edu.ng/api/app/check_request_availability', {
        params: {
          userid: user.id,
          matno: user.matric_number,
          destination: fields.mode === 'Hard' ? fields.destination : fields.mode,
        },
      })
      .then(function (response) {
        console.log(response)
        if (response.data.status === 'success') {
          fields.transcript_type === 'Official'
            ? setPaymentModal(!paymentModal)
            : handleStudentCopy()
        } else if (response.data.status === 'pin') {
          handleOfficialCopy(response.data.pin)
        } else {
          setError(true)
          setLoading(false)
          setMessage('You cannot proceed')
        }
      })
      .catch((err) => {
        setLoading(false)
        if (err.response) {
          setError(true)
          setMessage(err.response.data.message)
        } else {
          setError(true)
          setMessage('Network Error!')
        }
      })
  }

  const handleOfficialCopy = (rrr) => {
    const formData = new FormData()
    const config = {
      headers: {
        'content-type': 'multipart/form-data',
      },
    }
    fields.certificate &&
      formData.append('certificate', fields.certificate, fields.certificate.name)
    formData.append('userid', user.id)
    formData.append('matno', user.matric_number)
    formData.append('transcript_type', fields.transcript_type)
    formData.append('used_token', rrr)
    formData.append('mode', fields.mode)
    formData.append('recipient', fields.recipient)
    formData.append('destination', fields.mode === 'Hard' ? fields.destination : fields.mode)
    formData.append('address', fields.address)
    formData.append('graduation_year', fields.graduation_year)
    formData.append('reference', fields.reference)
    formData.append('gradstat', fields.gradstat)
    formData.append('institutional_username', fields.institutional_username)
    formData.append('institutional_password', fields.institutional_password)
    formData.append('email', fields.email)
    axios
      .post('https://records.run.edu.ng/api/app/submit_app', formData, config)
      .then(function (response) {
        console.log(response)
        setMessage(response.data.message)
        setLoading(false)
      })
      .catch((err) => {
        setLoading(false)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleStudentCopy = () => {
    if (fields.transcript_type === 'proficiency') {
      handleProficiency()
      return
    }
    axios
      .post('https://records.run.edu.ng/api/app/submit_app', {
        userid: user.id,
        matno: user.matric_number,
        transcript_type: fields.transcript_type,
      })
      .then(function (response) {
        setMessage(response.data.message)
        setLoading(false)
      })
      .catch((err) => {
        setLoading(false)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleProficiency = () => {
    const formData = new FormData()
    const config = {
      headers: {
        'content-type': 'multipart/form-data',
      },
    }
    formData.append('certificate', fields.certificate, fields.certificate.name)
    formData.append('userid', user.id)
    formData.append('matno', user.matric_number)
    formData.append('transcript_type', fields.transcript_type)
    formData.append('graduation_year', fields.graduation_year)
    axios
      .post('https://records.run.edu.ng/api/app/submit_app', formData, config)
      .then(function (response) {
        setMessage(response.data.message)
        setLoading(false)
      })
      .catch((err) => {
        setLoading(false)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleSubmit = (event) => {
    event.preventDefault()
    if (fields.transcript_type === '') return false
    const form = event.currentTarget
    if (form.checkValidity() === false) {
      event.stopPropagation()
      return
    }
    setValidated(true)
    checkApplicantValidity()
  }

  const closeModal = () => {
    setLoading(false)
    setPaymentModal(false)
  }

  return (
    <>
      <CCard className="mb-4">
        <CCardHeader>Application Form</CCardHeader>
        <CCardBody>
          <CForm noValidate validated={validated} onSubmit={handleSubmit}>
            <CRow className="g-3">
              <CCol xs>
                <CFormFloating className="mb-3">
                  <CFormInput
                    readOnly
                    defaultValue={user.surname + ' ' + user.firstname}
                    id="fullname"
                  />
                  <CFormLabel htmlFor="fullname">Fullname</CFormLabel>
                </CFormFloating>
              </CCol>
              <CCol xs>
                <CFormFloating className="mb-3">
                  <CFormInput readOnly defaultValue={studentDetails.PROGRAMME} id="programme" />
                  <CFormLabel htmlFor="programme">Programme</CFormLabel>
                </CFormFloating>
              </CCol>
            </CRow>

            <CRow className="g-3">
              <CCol xs>
                <CFormFloating className="mb-3">
                  <CFormSelect id="transcript_type" onChange={handleChange}>
                    <option value="">Select Transcript Type</option>
                    <option value="Student">Unofficial Transcript Request</option>
                    <option value="Official">Official Transcript Request</option>
                    <option value="proficiency">Proficiency in English Request</option>
                  </CFormSelect>
                  <CFormLabel htmlFor="transcript_type">Type</CFormLabel>
                </CFormFloating>
              </CCol>
              <CCol xs>
                {fields.transcript_type === 'Official' && (
                  <CFormFloating className="mb-3">
                    <CFormSelect id="mode" onChange={handleChange} required>
                      <option value="">Select Delivery Mode</option>
                      <option value="Soft">Soft Copy</option>
                      <option value="Portal">Portal Upload</option>
                      <option value="WES">WES Upload</option>
                      <option value="Hard">Hard Copy</option>
                    </CFormSelect>
                    <CFormLabel htmlFor="mode">Delivery Mode</CFormLabel>
                  </CFormFloating>
                )}
              </CCol>
            </CRow>

            <CRow className="g-3">
              <CCol xs>
                {fields.transcript_type === 'proficiency' && (
                  <CFormFloating className="mb-3">
                    <CFormInput
                      type="file"
                      size="sm"
                      id="certificate"
                      label="Upload Degree Certificate"
                      onChange={onFileChange}
                      required
                    />
                    <CFormLabel htmlFor="certificate">Upload Degree Certificate</CFormLabel>
                  </CFormFloating>
                )}
              </CCol>
              <CCol xs>
                {fields.transcript_type === 'proficiency' && (
                  <CFormFloating className="mb-3">
                    <CFormSelect id="graduation_year" onChange={handleChange} required>
                      <option value="">Select Graduation Year</option>
                      {yearList}
                    </CFormSelect>
                    <CFormLabel htmlFor="graduation_year">Graduation year</CFormLabel>
                  </CFormFloating>
                )}
              </CCol>
            </CRow>

            <CRow className="g-3">
              <CCol xs>
                {fields.transcript_type === 'Official' && (
                  <CFormFloating className="mb-3">
                    <CFormSelect id="gradstat" onChange={handleChange} required>
                      <option value="">Have you graduated?</option>
                      <option value="withdrew"> No,I Withdrew</option>
                      <option value="rusticated"> No, I was rusticated</option>
                      <option value="expelled"> No, I was expelled</option>
                      <option value="graduated">Yes, I have graduated</option>
                    </CFormSelect>
                    <CFormLabel htmlFor="gradstat">Student Status</CFormLabel>
                  </CFormFloating>
                )}
              </CCol>
              <CCol xs>
                {fields.transcript_type === 'Official' && fields.gradstat === 'graduated' && (
                  <CFormFloating className="mb-3">
                    <CFormSelect id="graduation_year" onChange={handleChange} required>
                      <option value="">Select Graduation Year</option>
                      {yearList}
                    </CFormSelect>
                    <CFormLabel htmlFor="graduation_year">Graduation year</CFormLabel>
                  </CFormFloating>
                )}
              </CCol>
            </CRow>

            {fields.transcript_type === 'Official' && fields.mode === 'Portal' && (
              <CRow className="g-3">
                <CCol xs>
                  <CFormFloating className="mb-3">
                    <CFormInput type="text" id="institutional_username" onChange={handleChange} />
                    <CFormLabel htmlFor="institutional_username">
                      Portal Username{' '}
                      <span style={{ color: 'red' }}>(Include portal link in parenthesis)</span>
                    </CFormLabel>
                  </CFormFloating>
                </CCol>
                <CCol xs>
                  <CFormFloating className="mb-3">
                    <CFormInput type="text" id="institutional_password" onChange={handleChange} />
                    <CFormLabel htmlFor="institutional_password">Portal Password</CFormLabel>
                  </CFormFloating>
                </CCol>
              </CRow>
            )}

            {fields.transcript_type === 'Official' && fields.mode === 'Soft' && (
              <CCol xs={12}>
                <CFormFloating className="mb-3">
                  <CFormInput type="email" id="email" onChange={handleChange} required />
                  <CFormLabel htmlFor="email">
                    Email address <span style={{ color: 'red' }}>(Official email address)</span>
                  </CFormLabel>
                </CFormFloating>
              </CCol>
            )}

            {fields.transcript_type === 'Official' && (
              <CCol xs={12}>
                <CFormFloating className="mb-3">
                  <CFormInput type="text" id="recipient" onChange={handleChange} required />
                  <CFormLabel htmlFor="recipient">Name of Institution/Organization</CFormLabel>
                </CFormFloating>
              </CCol>
            )}

            <CRow className="g-3">
              <CCol xs>
                {fields.transcript_type === 'Official' && (
                  <CFormFloating className="mb-3">
                    <CFormInput type="text" id="reference" onChange={handleChange} />
                    <CFormLabel htmlFor="reference">Reference Number</CFormLabel>
                  </CFormFloating>
                )}
              </CCol>
              <CCol xs>
                {fields.transcript_type === 'Official' &&
                  (fields.gradstat === 'graduated' || fields.gradstat === 'withdrew') && (
                    <CFormFloating className="mb-3">
                      <CFormInput
                        type="file"
                        size="sm"
                        id="certificate"
                        label="Upload Degree Certificate"
                        onChange={onFileChange}
                        required
                      />
                      <CFormLabel htmlFor="certificate">
                        {fields.gradstat === 'graduated'
                          ? 'Upload Degree Certificate'
                          : 'Upload Withdrawal Approval'}
                      </CFormLabel>
                    </CFormFloating>
                  )}
              </CCol>
            </CRow>

            <CRow className="g-3">
              {fields.transcript_type === 'Official' && fields.mode === 'Hard' && (
                <CCol xs>
                  <CFormFloating className="mb-3">
                    <CFormSelect id="destination" onChange={handleChange}>
                      <option value="">Select Destination</option>
                      {destFromServer.map((dest) => (
                        <option key={dest.value} data-amount={dest.amount} value={dest.value}>
                          {dest.desc}
                        </option>
                      ))}
                    </CFormSelect>
                    <CFormLabel htmlFor="destination">Destination</CFormLabel>
                  </CFormFloating>
                </CCol>
              )}
              {fields.transcript_type === 'Official' && fields.mode !== 'WES' && (
                <CCol>
                  <CFormFloating className="mb-3">
                    <CFormTextarea
                      id="address"
                      onChange={handleChange}
                      style={{ height: '100px' }}
                      defaultValue="e.g. The Registrar, Redeemers University, PMB 250, Akoda, Ede, Osun, Nigeria."
                      required
                    ></CFormTextarea>
                    <CFormLabel htmlFor="address">
                      Address{' '}
                      <span style={{ color: 'red' }}>
                        (Full office address of Institution/Organization)
                      </span>
                    </CFormLabel>
                  </CFormFloating>
                </CCol>
              )}
            </CRow>

            <hr></hr>
            <div className="d-grid">
              <CButton
                type="submit"
                shape="rounded-pill"
                variant="outline"
                color="warning"
                disabled={loading}
              >
                {loading && (
                  <CSpinner
                    component="span"
                    size="sm"
                    color="warning"
                    variant="grow"
                    aria-hidden="true"
                  />
                )}{' '}
                Submit
              </CButton>
            </div>
          </CForm>
        </CCardBody>
      </CCard>

      <CModal visible={paymentModal} onClose={() => closeModal()}>
        <CModalHeader onClose={() => closeModal()}>
          <CModalTitle>
            Proceed to Payment ({fields.mode === 'Hard' ? amount : '12000'})
          </CModalTitle>
        </CModalHeader>
        <CModalBody>
          <FlutterPayment
            amount="1000"
            email="toyxyboy@gmail.com"
            phone="08103947779"
            fullname="ToyosiAyo"
          />
          <RemitaConfig
            destination={fields.mode === 'Hard' ? fields.destination : fields.mode}
            amount={fields.mode === 'Hard' ? amount : '12000'}
            mode={fields.mode}
            transcript_type={fields.transcript_type}
            recipient={fields.recipient}
            address={fields.address}
            fields={fields}
          />
        </CModalBody>
        <CModalFooter>
          <CButton color="secondary" onClick={() => closeModal()}>
            Close
          </CButton>
        </CModalFooter>
      </CModal>
      <CToaster ref={toaster} push={toast} placement="top-end" />
    </>
  )
}

export default AppForm
