import React, { useState } from 'react'
import { useHistory } from 'react-router-dom'
import PropTypes from 'prop-types'
import axios from 'axios'
import { CButton, CSpinner } from '@coreui/react'
import { sha512 } from 'js-sha512'
import { getUser } from './Auth'
import Script from 'react-load-script'
// import { ImportScripts } from './ImportScripts'
const RemitaConfig = (props) => {
  const user = getUser()
  const [loading, setLoading] = useState(false)
  const history = useHistory()

  // const { RmPaymentEngine } = ImportScripts(
  //   'https://login.remita.net/payment/v1/remita-pay-inline.bundle.js',
  //   'Remita',
  // )

  // const externalJS = 'https://login.remita.net/payment/v1/remita-pay-inline.bundle.js'
  // const script = document.createElement('script')
  // script.src = externalJS
  // document.body.appendChild(script)

  const getConfig = async () => {
    setLoading(true)
    await axios
      .get('https://records.run.edu.ng/api/app/get_gateway_config', {
        params: {
          gateway: 'remita',
          userid: user.id,
          destination: props.destination,
          matno: user.matric_number,
          mode: props.mode,
        },
      })
      .then(function (response) {
        if (response.data.status === 'success') {
          checkRRR(response.data.data)
        }
      })
  }

  const checkRRR = (data) => {
    axios
      .post('https://records.run.edu.ng/api/app/check_pend_rrr', {
        userid: user.id,
        matno: user.matric_number,
        gateway: 'remita',
        destination: props.destination,
        mode: props.mode,
      })
      .then(function (response) {
        console.log(response)
        if (response.data.status === 'success') {
          makePayment(response.data.p_rrr)
        } else {
          if (confirm('Proceed to get RRR') == false) {
            setLoading(false)
            return false
          }
          //alert('Proceed to get RRR')
          getRRR(data)
        }
      })
      .catch((err) => {
        setLoading(false)
        if (err.response) {
          alert(err.response.data.message)
        } else {
          alert('Network Error!')
        }
      })
  }

  const getRRR = (data) => {
    console.log(data)
    sessionStorage.setItem('orderID', data.orderID)
    let apiHash = sha512(
      data.merchantId + data.serviceTypeID + data.orderID + props.amount + data.apiKey,
    )
    var myHeaders = new Headers()
    myHeaders.append('Content-Type', 'application/json')
    myHeaders.append(
      'Authorization',
      `remitaConsumerKey=${data.merchantId},remitaConsumerToken=${apiHash}`,
    )
    var desc = 'Transcript Request Payment'
    var raw = JSON.stringify({
      serviceTypeId: data.serviceTypeID,
      amount: props.amount,
      orderId: data.orderID,
      payerName: user.surname + user.firstname,
      payerEmail: user.email,
      payerPhone: user.mobile,
      description: desc,
    })

    var requestOptions = {
      method: 'POST',
      headers: myHeaders,
      body: raw,
      redirect: 'follow',
    }

    fetch(
      //'https://login.remita.net/remita/exapp/api/v1/send/api/echannelsvc/merchant/api/paymentinit',
      'https://remitademo.net/remita/exapp/api/v1/send/api/echannelsvc/merchant/api/paymentinit',
      requestOptions,
    )
      .then((response) => response.text())
      .then((result) => {
        console.log(result)
        saveRRR(result)
      })
      .catch((error) => console.log('error', error))
  }

  const saveRRR = (data) => {
    const obj = data.substring(7, data.length - 1)
    const objJson = JSON.parse(obj)
    const orderID = sessionStorage.getItem('orderID')
    axios
      .post('https://records.run.edu.ng/api/app/log_new_rrr_trans_ref', {
        userid: user.id,
        gateway: 'remita',
        destination: props.destination,
        matno: user.matric_number,
        rrr: objJson.RRR,
        orderID: orderID,
        amount: props.amount,
        statuscode: objJson.statuscode,
        statusMsg: objJson.status,
      })
      .then((res) => {
        console.log(res)
        makePayment(objJson.RRR)
      })
      .catch((err) => {
        console.log(err)
        alert('Error logging your payment')
        setLoading(false)
      })
  }

  const makePayment = (rrr) => {
    var paymentEngine = RmPaymentEngine.init({
      //'QzAwMDAxNjMwNzl8NDA4NDEyMjQ0MHw0ODZkYTZkOTE4NTVhNzMzZmIzZTM5MTU2ZDBjZDYxY2Y4MzY4ODQ1NzRkYzIyOTI2OWQzMTU1M2NlNzdkNGZkZGIyNjI1MzA1ZjZkNzkzYzM2NTE4NzUxNTI0OWVjYjAxODUyNGZmYTM3NjY3M2IwZWNjYTU3OWEwYjE5NGMyNQ==',
      key: 'QzAwMDAxNTY4NzN8OTU3M3w1OWUwZmVmMmUxYWYwZTlhMjk3MTU5MzIwNzcxNjc1NWYwYmI5ZWNkZWYyYzcwYWZiZGIwOGZkYmViYzhiYjI3MTkyYzA3MGRhOWZkZDgxNDhlMjdjNmVkMGI0ZjgwYjQ4ZDM1OTkwMzhmNzU4OTJmN2NjMTUxMTljZDY1NjA1NQ==',
      customerId: user.matric_number,
      firstName: user.firstname,
      lastName: user.surname,
      email: user.email,
      narration: 'Transcript Request Payment',
      amount: props.amount,
      processRrr: true,
      extendedData: {
        customFields: [
          {
            name: 'rrr',
            value: rrr,
          },
        ],
      },
      onSuccess: (response) => {
        console.log(response)
        if (response.transactionId == '') {
          setLoading(false)
          return false
        }
        axios
          .post('https://records.run.edu.ng/api/app/update_payment', {
            matno: user.matric_number,
            paymentReference: rrr,
            transactionId: response.transactionId,
          })
          .then((res) => {
            console.log(res)
            if (res.data.status === 'success') {
              const formData = new FormData()
              const config = {
                headers: {
                  'content-type': 'multipart/form-data',
                },
              }
              props.fields.certificate &&
                formData.append(
                  'certificate',
                  props.fields.certificate,
                  props.fields.certificate.name,
                )
              formData.append('userid', user.id)
              formData.append('matno', user.matric_number)
              formData.append('transcript_type', props.transcript_type)
              formData.append('used_token', rrr)
              formData.append('mode', props.mode)
              formData.append('recipient', props.recipient)
              formData.append('destination', props.destination)
              formData.append('address', props.address)
              formData.append('graduation_year', props.fields.graduation_year)
              formData.append('reference', props.fields.reference)
              formData.append('gradstat', props.fields.gradstat)
              formData.append('institutional_username', props.fields.institutional_username)
              formData.append('institutional_password', props.fields.institutional_password)
              formData.append('email', props.fields.email)

              axios
                .post('https://records.run.edu.ng/api/app/submit_app', formData, config)
                .then(function (response) {
                  console.log(response)
                  alert(response.data.message)
                  setLoading(false)
                  history.push('/application')
                })
                .catch((err) => {
                  setLoading(false)
                  //setError(true)
                  if (err.response) {
                    alert(err.response.data.message)
                  } else {
                    alert('Network Error!')
                  }
                })
            }
          })
          .catch((err) => {
            console.log(err)
          })
      },
      onError: (response) => {
        console.log(response)
        setLoading(false)
      },
      onClose: function () {
        console.log('closed')
        setLoading(false)
      },
    })
    paymentEngine.showPaymentWidget()
  }

  return (
    <div>
      <Script
        //url="https://login.remita.net/payment/v1/remita-pay-inline.bundle.js"
        url="https://remitademo.net/payment/v1/remita-pay-inline.bundle.js"
        onCreate={console.log('created')}
        onError={console.log('error')}
        onLoad={console.log('loaded')}
      />
      <img
        style={{ width: '20%' }}
        className="text-align:left p-3"
        src="https://dailypost.ng/wp-content/uploads/2019/02/Remita-Logo.png.webp"
        alt="logo"
      />
      <CButton type="button" color="success" onClick={() => getConfig()} disabled={loading}>
        {loading && (
          <CSpinner component="span" size="sm" color="light" variant="grow" aria-hidden="true" />
        )}{' '}
        Pay with Remita
      </CButton>
    </div>
  )
}

RemitaConfig.propTypes = {
  destination: PropTypes.string,
  amount: PropTypes.any,
  mode: PropTypes.string,
  transcript_type: PropTypes.string,
  recipient: PropTypes.string,
  address: PropTypes.string,
  fields: PropTypes.any,
}

export default RemitaConfig
